The following program implements the topological sort algorithm with a stack. Please fill in the blanks.

```c
void Topsort(int a[NUM][NUM], int TopNum[NUM])
// a[NUM][NUM] is adjacency matrix of the graph with NUM vertices
// TopNum[NUM] stores the topological orders
{
    int S[NUM], Indegree[NUM]; // S[NUM] is a stack
    int Counter = 0, top, n, i, j;
    int V;
    top = -1;
    n = NUM;
    for (j = 0; j < n; j++) {
        Indegree[j] = 0;
        for (i = 0; i < n; i++)
            if (a[i][j] != __blank1__) Indegree[j]++;
        if (Indegree[j] == 0) S[++top] = j;
    }
    while (top >= 0) {
        V = S[top--];
        TopNum[V] = ++Counter;
        for (j = 0; j < n; j++)
            if (a[V][j] != 0)
                if (--Indegree[__blank2__] == 0) S[++top] = j;
    }
    if (Counter != n) printf("Graph has a cycle");
}
```

Blank 1: condition to check for an edge
Blank 2: index for Indegree decrement

The function is to sort the array A in descending order. The function Swap(&A[0], &A[i]) is to exchange A[0] and A[i]. Please complete the following program.

```c
#define leftchild(i) (2*(i)+1)
void PercDown(ElementType A[], int i, int N)
{
    int child;
    ElementType tmp;
    for (tmp = A[i]; leftchild(i) < N; i = child) {
        child = leftchild(i);
        if (child != N-1 && A[child] < A[__blank1__])
            child++;
        if (tmp > A[child])
            A[i] = A[child];
        else break;
    }
    A[i] = tmp;
}

void Heapsort(ElementType A[], int N)
{
    int i;
    for (i = N / 2; i >= 0; i--)
        PercDown(A, i, N);
    for (i = N - 1; i > 0; i--) {
        Swap(&A[0], &A[i]);
        PercDown(A, __blank2__);
    }
}
```

Blank 1: comparison for choosing the smaller child (min-heap for descending sort)
Blank 2: arguments for PercDown after swap

Given a binary search tree $T$, you are supposed to output all the elements in the left subtree of x, in ascending order.

Format of functions:
```c
void print_left_subtree(Tree T, int X);
```

where Tree is defined as:
```c
typedef struct TreeNode *Tree;
struct TreeNode {
    int element;
    Tree left;
    Tree right;
};
```

Sample Input:
```
7
90 80 91 55 70 85 92
80
```

Sample Output:
```
55 70 end
```

For an empty tree, simply output: `empty tree`
In case x is not found in T, output: `x not found`

answer.codeSnippet:
void inorder_print(Tree T) {
    if (T == NULL) return;
    inorder_print(T->left);
    printf("%d ", T->element);
    inorder_print(T->right);
}

void print_left_subtree(Tree T, int X) {
    if (T == NULL) {
        printf("empty tree\n");
        return;
    }
    // Find node X in BST
    Tree node = T;
    while (node != NULL && node->element != X) {
        if (X < node->element)
            node = node->left;
        else
            node = node->right;
    }
    if (node == NULL) {
        printf("x not found\n");
        return;
    }
    if (node->left == NULL) {
        printf("end\n");
        return;
    }
    inorder_print(node->left);
    printf("end\n");
}
